sys_script_include.script:
var DataLakeUtils = Class.create();
DataLakeUtils.prototype = {

    TABLE_NAME: 'x_ctans_incentnow_data_lake',
    EXCLUDED_FIELDS: [
        'sys_created_by',
        'sys_created_on',
        'sys_updated_by',
        'sys_updated_on',
        'processing_status',
        'number',
		'transaction_date',
        'raw_payload',
        'sys_mod_count',
        'sys_id'
    ],

    initialize: function() {},

    filterColumnsbyType: function(fieldTypeSysId) {

        var query = 'name=' + this.TABLE_NAME;

        if (fieldTypeSysId) {
            var typeGR = new GlideRecordSecure('sys_glide_object');
            if (typeGR.get(fieldTypeSysId)) {
                query += '^internal_type=' + typeGR.getValue('name');
            }
        }

        // Build NOT IN dynamically
        query += '^elementNOT IN' + this.EXCLUDED_FIELDS.join(',');

        query += '^ORDERBYelement';

        return query;
    },

	applyColumnFilter: function(grDB, fieldTypeSysId) {

    grDB.addQuery('name', this.TABLE_NAME);

    if (fieldTypeSysId) {
        var typeGR = new GlideRecordSecure('sys_glide_object');
        if (typeGR.get(fieldTypeSysId)) {
            grDB.addQuery('internal_type', typeGR.getValue('name'));
        }
    }

    grDB.addQuery(
        'element',
        'NOT IN',
        this.EXCLUDED_FIELDS.join(',')
    );

    grDB.orderBy('element');
	},

    type: 'DataLakeUtils'
};
